// Validate incoming webhook data
const data = $input.all();

if (!data || !data[0] || !data[0].json || !data[0].json.messages) {
  throw new Error('Invalid input: messages array required');
}

const messages = data[0].json.messages;
const validationMode = data[0].json.validation_mode || 'strict';

if (!Array.isArray(messages) || messages.length === 0) {
  throw new Error('messages must be a non-empty array');
}

return [{
  json: {
    messages,
    validationMode,
    timestamp: new Date().toISOString()
  }
}];

// Transform Python agent response for output
const data = $input.all()[0].json;

// Extract key metrics
const stats = data.stats || {};
const failed = data.failed || [];
const messages = data.messages || [];

// Group messages by provider
const byProvider = {};
messages.forEach(msg => {
  if (!byProvider[msg.provider]) {
    byProvider[msg.provider] = [];
  }
  byProvider[msg.provider].push(msg);
});

// Count tool calls
const toolCallCount = messages.reduce((acc, msg) => {
  return acc + (msg.toolCalls ? msg.toolCalls.length : 0);
}, 0);

return [{
  json: {
    status: data.status,
    summary: {
      total: stats.total,
      succeeded: stats.succeeded,
      failed: stats.failed,
      toolCalls: toolCallCount,
      byProvider: Object.keys(byProvider).map(provider => ({
        provider,
        count: byProvider[provider].length
      }))
    },
    messages,
    failed,
    processedAt: new Date().toISOString()
  }
}];

// Handle errors gracefully
const error = $input.all()[0].error;

return [{
  json: {
    status: 'error',
    message: error?.message || 'Unknown error occurred',
    timestamp: new Date().toISOString()
  }
}];
